patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..268988a7a85f 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -436,7 +436,6 @@ static Value *threadBinOpOverSelect(Instruction::BinaryOps Opcode, Value *LHS,

   // If one branch simplified and the other did not, and the simplified
   // value is equal to the unsimplified one, return the simplified value.
-  // For example, select (cond, X, X & Z) & Z -> X & Z.
   if ((FV && !TV) || (TV && !FV)) {
     // Check that the simplified value has the form "X op Y" where "op" is the
     // same as the original operation.
@@ -4628,6 +4627,14 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
     // select i1 X, i1 false, i1 X --> false
     if (match(TrueVal, m_ZeroInt()))
       return ConstantInt::getFalse(Cond->getType());
+
+  }
+  // select (select C, A, false), true, C -> C
+  // (C && A) || C = C
+  Value *A;
+  if (match(Cond, m_Select(m_Specific(FalseVal), m_Value(A), m_Zero())) &&
+      match(TrueVal, m_One()))
+    return FalseVal;
   }

   // If the true or false value is poison, we can fold to the other value.

